import{_ as t,o as s,c as a,ag as o}from"./chunks/framework.B3ZMliSr.js";const u=JSON.parse('{"title":"Updates","description":"getUpdates, the persistent update queue (TQueue), update types, and allowed_updates filtering.","frontmatter":{"title":"Updates","description":"getUpdates, the persistent update queue (TQueue), update types, and allowed_updates filtering."},"headers":[],"relativePath":"bot-api/updates.md","filePath":"bot-api/updates.md","lastUpdated":1783313024000}'),i={name:"bot-api/updates.md"};function n(l,e,d,p,c,r){return s(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h1><p>Updates flow through a <strong>monotonic update queue (TQueue)</strong> that persists every event to SQLite on push. On restart, the queue replays undelivered events — no updates are lost across crashes or deploys.</p><h2 id="getupdates" tabindex="-1">getUpdates <a class="header-anchor" href="#getupdates" aria-label="Permalink to &quot;getUpdates&quot;">​</a></h2><p>Long-poll for updates:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Poll with a 30-second timeout</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://localhost:8081/bot&lt;TOKEN&gt;/getUpdates?timeout=30&amp;offset=&lt;LAST_ID+1&gt;&quot;</span></span></code></pre></div><p>The request blocks for up to <code>timeout</code> seconds (default <code>0</code>) until an update is available, shaped exactly like the official server — including the 3-second delayed conflict response and a 50-second hard cap.</p><h2 id="tqueue-guarantees" tabindex="-1">TQueue guarantees <a class="header-anchor" href="#tqueue-guarantees" aria-label="Permalink to &quot;TQueue guarantees&quot;">​</a></h2><ul><li><strong>Persistent</strong> — every event is written to SQLite on push. On restart the queue replays undelivered events.</li><li><strong>Monotonic IDs</strong> — <code>update_id</code> values are strictly increasing per bot. Clients acknowledge by passing <code>offset = last_update_id + 1</code>.</li><li><strong>Long polling</strong> — <code>getUpdates</code> blocks for up to <code>timeout</code> seconds, matching the official server&#39;s timing (3-second delayed conflict, 50-second hard cap).</li><li><strong>Conflict detection</strong> — a second concurrent <code>getUpdates</code> (with an older offset) gets HTTP <code>409 Conflict</code>. Webhook-active bots get <code>409</code> on <em>any</em><code>getUpdates</code> call.</li><li><strong>Negative offset</strong> — passing <code>offset &lt; 0</code> clears the queue but keeps the newest events.</li><li><strong>Size budget</strong> — a single <code>getUpdates</code> response is capped at ~4 MB (<code>1 &lt;&lt; 22</code> bytes), truncating the event list if it overflows.</li></ul><div class="tip custom-block"><p class="custom-block-title">Offset semantics</p><p><code>offset = update_id + 1</code> confirms receipt of <code>update_id</code> and all prior events. Once confirmed, those events are removed from the queue. A negative offset wipes the queue while retaining the most recent events for the next poll.</p></div><h2 id="update-types" tabindex="-1">Update types <a class="header-anchor" href="#update-types" aria-label="Permalink to &quot;Update types&quot;">​</a></h2><p>All <strong>22</strong> Bot API update types are delivered via <code>getUpdates</code> and webhooks:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>message                    deleted_business_messages   message_reaction_count</span></span>
<span class="line"><span>edited_message             callback_query              poll</span></span>
<span class="line"><span>channel_post               inline_query                poll_answer</span></span>
<span class="line"><span>edited_channel_post        chosen_inline_result        business_connection</span></span>
<span class="line"><span>business_message           chat_join_request           chat_boost</span></span>
<span class="line"><span>edited_business_message    chat_member                 removed_chat_boost</span></span>
<span class="line"><span>my_chat_member             shipping_query</span></span>
<span class="line"><span>                           pre_checkout_query</span></span></code></pre></div><h2 id="allowed-updates-filtering" tabindex="-1">allowed_updates filtering <a class="header-anchor" href="#allowed-updates-filtering" aria-label="Permalink to &quot;allowed_updates filtering&quot;">​</a></h2><p><code>allowed_updates</code> controls which update types are delivered. Filtering applies at push time (in the TQueue) and is persisted per webhook.</p><table tabindex="0"><thead><tr><th><code>allowed_updates</code> value</th><th>Behavior</th></tr></thead><tbody><tr><td><code>nil</code> / empty / omitted</td><td><strong>Default set</strong> — excludes <code>chat_member</code>, <code>message_reaction</code>, <code>message_reaction_count</code>, <code>chat_boost</code>, <code>removed_chat_boost</code></td></tr><tr><td>Non-nil array</td><td><strong>Only</strong> the listed types are delivered</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Receive only messages and callback queries</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8081/bot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TOKE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">N</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/getUpdates</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;allowed_updates=[&quot;message&quot;,&quot;callback_query&quot;]&#39;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Setting <code>allowed_updates</code> to a non-empty array is a <em>whitelist</em>: anything not listed is dropped at push time. To receive the default set plus extra types, list the defaults explicitly alongside the extras.</p></div><h2 id="webhook-vs-polling" tabindex="-1">Webhook vs. polling <a class="header-anchor" href="#webhook-vs-polling" aria-label="Permalink to &quot;Webhook vs. polling&quot;">​</a></h2><p>A bot may use <strong>either</strong> <code>getUpdates</code> <strong>or</strong> a webhook, never both. The server enforces this:</p><ul><li>An active webhook causes <code>getUpdates</code> to return <code>409 Conflict</code>.</li><li>Calling <code>setWebhook</code> while <code>getUpdates</code> is mid-poll cancels the poll.</li></ul><p>See <a href="/website/bot-api/webhooks">Webhooks</a> for the webhook delivery model.</p>`,21)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
